In this section, you can learn how to create a MongoDB Search index named `default` on
all the fields in the `companies` collection in the
`sample_training` database. You will create another MongoDB Search index
named `default` on all the fields in the `inspections`
collection in the `sample_training` database.

In your terminal, navigate to where you want to create your application,
then run the following command to create a directory called
`search-with-unionwith` for this project:

```shell
mkdir search-with-unionwith
cd search-with-unionwith
```

Add the C driver to your project by following the instructions in the
[MongoDB C Driver documentation](languages/c/c-driver/current/get-started).

Create a `create_indexes.c` file in your project directory,
and copy and paste the following code into the file.

```c
#include <mongoc/mongoc.h>
#include <stdio.h>

int main(int argc, char *argv[]) {
    mongoc_client_t *client;
    mongoc_collection_t *collection1;
    mongoc_collection_t *collection2;
    bson_error_t error;
    bson_t cmd1;
    bson_t cmd2;
    bson_t *index_definition;
    bool success;

    /* Initialize the MongoDB C Driver. */
    mongoc_init();

    /* Connect to your MongoDB deployment. */
    client = mongoc_client_new("<connection-string>");
    collection1 = mongoc_client_get_collection (client, "sample_training", "companies");
    collection2 = mongoc_client_get_collection (client, "sample_training", "inspections");

    if (!client) {
        fprintf(stderr, "Failed to create client.\n");
        return 1;
    }

    /* Create the MongoDB Search index definitions. */
    char *cmd_str1 = bson_strdup_printf (
        BSON_STR ({
            "createSearchIndexes": "%s",
            "indexes": [{
                "name": "default",
                "definition": {
                    "mappings": {
                        "dynamic": true
                    }
                }
            }]
        }),
        "companies"
    );
    char *cmd_str2 = bson_strdup_printf (
        BSON_STR ({
            "createSearchIndexes": "%s",
            "indexes": [{
                "name": "default",
                "definition": {
                    "mappings": {
                        "dynamic": true
                    }
                }
            }]
        }),
        "inspections"
    );

    bson_init_from_json (&cmd1, cmd_str1, -1, &error);
    bson_init_from_json (&cmd2, cmd_str2, -1, &error);
    bson_free (cmd_str1);
    bson_free (cmd_str2);

    if (mongoc_collection_command_simple (collection1, &cmd1, NULL, NULL, &error)) {
        printf ("Index created on the companies collection!\n");
    } else {
        fprintf (stderr, "Failed to create search index: %s", error.message);
    }

    if (mongoc_collection_command_simple (collection2, &cmd2, NULL, NULL, &error)) {
        printf ("Index created on the inspections collection!\n");
    } else {
        fprintf (stderr, "Failed to create search index: %s", error.message);
    }

    /* Clean up. */
    bson_destroy (&cmd1);
    bson_destroy (&cmd2);
    mongoc_collection_destroy (collection1);
    mongoc_collection_destroy (collection2);
    mongoc_client_destroy(client);
    mongoc_cleanup();

    return 0;
}
```

Replace `<connection-string>` with the connection string for your
Atlas cluster or local Atlas deployment.

Atlas Cluster

Your connection string should use the following format:

```
mongodb+srv://<db_username>:<db_password>@<clusterName>.<hostname>.mongodb.net
```

To learn more, see [Driver](connect-via-driver).

Local or Self-Managed

Your connection string should use the
following format:

```
mongodb://localhost:<port-number>/?directConnection=true
```

To learn more, see [Connection Strings](manual/reference/connection-string).

To configure your application, create a `CMakeLists.txt` file in
your project directory. Then, add the following code to the file:

```txt
cmake_minimum_required(VERSION 3.11)
project(search-with-unionwith LANGUAGES C)
add_executable (index.out create_indexes.c)
find_package(mongoc <version> REQUIRED)
target_link_libraries(index.out mongoc::mongoc)

```

The preceding code performs the following actions:

- Configures a C project.

- Creates a `index.out` executable for your application.

- Finds and requires the C driver. Replace the `<version>`
  placeholder with your C driver version, such as `2.0.0`.

- Links the program to the `libmongoc` library.

> **Note:** In the sample `CMakeLists.txt` file, the `mongoc::mongoc` target
> points to either the static library or the shared library.
> The library type depends on which one is available and
> whichever type the user specifies in the `MONGOC_DEFAULT_IMPORTED_LIBRARY_TYPE`
> CMake configuration setting. If you don't set this value and
> both library types are available, `mongoc::mongoc` uses
> the static library.
>
> You can use the `mongoc::static` target to explicitly use the
> static library or the `mongoc::shared` target to use the shared
> library.

In your terminal, run the following commands to build and run this
application:

**Input:**

```shell
cmake -S. -Bcmake-build
cmake --build cmake-build --target index.out
./cmake-build/index.out
```

**Output:**

```
Index created on the companies collection!
Index created on the inspections collection!
```

